#!/usr/bin/env node
// Regenerates the tokens consumed by:
//   - app/renderer.js          via app/lib/tokens-window.js  (window.TT_TOKENS)
//   - docs/ui-kit/palette.js   via docs/ui-kit/tokens.mjs    (ESM export)
//   - docs/colors_and_type.css via a marker-bounded GENERATED PALETTE block
//
// Source of truth: app/lib/tokens.json. Edit that, then run this.
// All three outputs are deterministic from the JSON, so a CI run that
// regenerates and diffs will catch hand-edits to the generated files.

const fs   = require('fs');
const path = require('path');

const ROOT            = path.resolve(__dirname, '..');
const SRC             = path.join(ROOT, 'app', 'lib', 'tokens.json');
const OUT_WIN_JS      = path.join(ROOT, 'app', 'lib', 'tokens-window.js');
const OUT_KIT         = path.join(ROOT, 'docs', 'ui-kit', 'tokens.mjs');
const OUT_CSS         = path.join(ROOT, 'docs', 'colors_and_type.css');
// D2-9 — palette-index CSS classes that the renderer consumes via
// data-palette attribute rather than inline `style.background = ...`.
// Keeps `'unsafe-inline'` out of the CSP style-src directive.
const OUT_PALETTE_CSS = path.join(ROOT, 'app', 'lib', 'palette-classes.css');

const BEGIN = '/* === BEGIN GENERATED PALETTE — do not edit (run scripts/generate-tokens-css.cjs) === */';
const END   = '/* === END GENERATED PALETTE === */';

const tokens  = JSON.parse(fs.readFileSync(SRC, 'utf8'));
const palette = tokens.palette;

// --- output 1: window-global for the Electron renderer (no module system).
const winJs =
`// GENERATED by scripts/generate-tokens-css.cjs from app/lib/tokens.json.
// Do not hand-edit. Loaded by app/index.html before renderer.js.
window.TT_TOKENS = Object.freeze(${JSON.stringify(tokens, null, 2)});
`;
fs.writeFileSync(OUT_WIN_JS, winJs);

// --- output 2: ESM for the docs/ui-kit React demo.
const kit =
`// GENERATED by scripts/generate-tokens-css.cjs from app/lib/tokens.json.
// Do not hand-edit. Imported by docs/ui-kit/palette.js.
export const TOKENS = Object.freeze(${JSON.stringify(tokens, null, 2)});
export const PALETTE = TOKENS.palette;
`;
fs.writeFileSync(OUT_KIT, kit);

// --- output 3: palette block inside docs/colors_and_type.css.
//   - 8 base colour vars   (--tt-palette-base-NN)
//   - 24 arrangement vars  (--tt-palette-NN-bg) as ready-to-use background values
function arrangementBg(i) {
  const { BASE_COLOURS, HSPLIT_PARTNER, VSPLIT_PARTNER } = palette;
  if (i < 8)  return BASE_COLOURS[i];
  if (i < 16) {
    const p = i - 8;
    return `linear-gradient(to bottom, ${BASE_COLOURS[p]} 50%, ${BASE_COLOURS[HSPLIT_PARTNER[p]]} 50%)`;
  }
  const p = i - 16;
  return `linear-gradient(to right, ${BASE_COLOURS[p]} 50%, ${BASE_COLOURS[VSPLIT_PARTNER[p]]} 50%)`;
}

const baseLines = palette.BASE_COLOURS
  .map((hex, i) => `  --tt-palette-base-${String(i).padStart(2, '0')}: ${hex};   /* ${palette.COLOUR_NAMES[i]} */`)
  .join('\n');

const arrangementLines = Array.from({ length: palette.PALETTE_SIZE }, (_, i) =>
  `  --tt-palette-${String(i).padStart(2, '0')}-bg: ${arrangementBg(i)};`,
).join('\n');

const generatedBlock =
`${BEGIN}
:root {
${baseLines}

  --tt-palette-neutral: ${palette.NEUTRAL_COLOUR};

${arrangementLines}
}
${END}`;

let css;
try { css = fs.readFileSync(OUT_CSS, 'utf8'); }
catch { css = ''; }

if (css.includes(BEGIN) && css.includes(END)) {
  // Replace existing generated block in-place.
  const before = css.split(BEGIN)[0];
  const after  = css.split(END)[1] ?? '';
  css = before + generatedBlock + after;
} else {
  // First run: append a newline-padded block at the end of the file.
  const trimmed = css.replace(/\s+$/, '');
  css = `${trimmed}\n\n${generatedBlock}\n`;
}
fs.writeFileSync(OUT_CSS, css);

// --- output 4: palette-index classes for the renderer (D2-9).
// Two rule families:
//   [data-palette="NN"]            background: <arrangement>
//   .dot.heard[data-palette="NN"]  border-color + box-shadow use primary
// The primary colour for solids is the solid itself. For splits it's
// the first colour (same as app/renderer.js:primaryColourForArrangement).
// EX5 — primary colour used for heard-clip border + box-shadow. Takes
// which palette set (default or CB) to pull from as a parameter so the
// CB rules can reuse this for their own heard-rings.
function primaryForArrangement(i, baseColours) {
  if (i < 8)  return baseColours[i];
  if (i < 16) return baseColours[i - 8];
  return baseColours[i - 16];
}

// EX5 — arrangementBg now takes the colour set as a param so we can
// emit both default and CB rule blocks from the same helper.
function arrangementBgFor(i, baseColours) {
  const { HSPLIT_PARTNER, VSPLIT_PARTNER } = palette;
  if (i < 8)  return baseColours[i];
  if (i < 16) {
    const p = i - 8;
    return `linear-gradient(to bottom, ${baseColours[p]} 50%, ${baseColours[HSPLIT_PARTNER[p]]} 50%)`;
  }
  const p = i - 16;
  return `linear-gradient(to right, ${baseColours[p]} 50%, ${baseColours[VSPLIT_PARTNER[p]]} 50%)`;
}

function emitPaletteRules(baseColours, selectorPrefix) {
  const lines = [];
  for (let i = 0; i < palette.PALETTE_SIZE; i++) {
    const k = String(i).padStart(2, '0');
    const bg = arrangementBgFor(i, baseColours);
    const primary = primaryForArrangement(i, baseColours);
    lines.push(`${selectorPrefix}[data-palette="${k}"] { background: ${bg}; }`);
    lines.push(`${selectorPrefix}.dot.heard[data-palette="${k}"] { border-color: ${primary}; box-shadow: 0 0 0 2px ${primary}; }`);
  }
  lines.push(`${selectorPrefix}[data-palette="neutral"] { background: ${palette.NEUTRAL_COLOUR}; }`);
  lines.push(`${selectorPrefix}.dot.heard[data-palette="neutral"] { border-color: ${palette.NEUTRAL_COLOUR}; box-shadow: 0 0 0 2px ${palette.NEUTRAL_COLOUR}; }`);
  return lines;
}

// Default palette: unprefixed selectors (applies always).
const defaultLines = emitPaletteRules(palette.BASE_COLOURS, '');

// CB palette: prefixed with body[data-palette-variant="cb"]. Higher
// specificity than the default rules so it wins when the body attr
// is set. Users opt in via the Settings > Playback toggle; default
// users are unaffected.
const cbLines = palette.BASE_COLOURS_CB
  ? emitPaletteRules(palette.BASE_COLOURS_CB, 'body[data-palette-variant="cb"] ')
  : [];

const paletteCss =
`/* GENERATED by scripts/generate-tokens-css.cjs from app/lib/tokens.json.
   Do not hand-edit. Loaded by app/index.html via <link rel="stylesheet">.
   D2-9 — replaces inline .style.background / .style.boxShadow writes in
   renderer.js so the CSP style-src directive doesn't need unsafe-inline.
   EX5 — when body[data-palette-variant="cb"] is set, the CB-safe rules
   below override the default palette. Default users never see them. */
/* Default palette (applies always unless overridden below) */
${defaultLines.join('\n')}

/* Colour-blind-friendly palette (Paul Tol "muted") — only applies when
   body has data-palette-variant="cb". Users opt in via Settings. */
${cbLines.join('\n')}
`;
fs.writeFileSync(OUT_PALETTE_CSS, paletteCss);

console.log(`tokens generated:
  ${path.relative(ROOT, OUT_WIN_JS)}
  ${path.relative(ROOT, OUT_KIT)}
  ${path.relative(ROOT, OUT_CSS)}  (palette block)
  ${path.relative(ROOT, OUT_PALETTE_CSS)}  (renderer class rules, D2-9)`);
